import bisect
class Solution:
    def minOperations(self, nums):
        n = len(nums)
        uniq = sorted(set(nums))
        m = len(uniq)
        best = 0
        for i in range(m):
            limit = uniq[i] + n - 1
            j = bisect.bisect_right(uniq, limit) - 1
            if j - i + 1 > best:
                best = j - i + 1
        return n - best

