var minOperations = function(nums) {
    const n = nums.length;
    const uniq = Array.from(new Set(nums)).sort((a, b) => a - b);
    const m = uniq.length;
    let best = 0;
    for (let i = 0; i < m; i++) {
        const limit = uniq[i] + n - 1;
        let lo = i, hi = m;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (uniq[mid] <= limit) lo = mid + 1;
            else hi = mid;
        }
        const j = lo - 1;
        if (j - i + 1 > best) best = j - i + 1;
    }
    return n - best;
};
